#include <stdio.h>
#include <limits.h>
#define MOD 1000000007
int min(int a, int b) { return a < b ? a : b; }
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        int A[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        long long dp[N];
        dp[0] = A[0];
        for (int i = 1; i < N; i++) {
            dp[i] = LLONG_MAX;
            for (int j = 1; j <= K && i - j >= 0; j++) {
                dp[i] = min(dp[i], dp[i - j] * A[i] % MOD);
            }
        }
        printf("%lld\n", dp[N - 1]);
    }
    return 0;
}

