import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int K = sc.nextInt();
            int[] A = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextInt();
            }
            long[] dp = new long[N];
            dp[0] = A[0];
            for (int i = 1; i < N; i++) {
                dp[i] = Long.MAX_VALUE;
                for (int j = 1; j <= K && i - j >= 0; j++) {
                    dp[i] = Math.min(dp[i], dp[i - j] * A[i] % 1000000007);
                }
            }
            System.out.println(dp[N - 1]);
        }
    }
}

